mapper.select:
SELECT id, merchant_no, merchant_name, parent_merchant_no, parent_merchant_name, agent_level, agent_path, commission_rate, status, remark, created_at, updated_at, deleted FROM agent_relation
deleted = 0
AND merchant_no = #{params.merchantNo}
AND merchant_name LIKE CONCAT('%', #{params.merchantName}, '%')
AND parent_merchant_no = #{params.parentMerchantNo}
AND agent_level = #{params.agentLevel}
AND status = #{params.status}
ORDER BY created_at DESC
